const data = $input.first().json;
const endpoints = data.endpoints || [];

// 1. مرحلة الفلترة الذكية والموجهة جداً للـ IDOR
const suspicious = endpoints.filter(ep => {
  const url = (ep.url || '').toLowerCase();
  const method = (ep.method || 'GET').toUpperCase();

  // أخذ اسم الملف فقط وتجاهل الدومين تماماً
  const filename = url.split('/').pop().split('?')[0];

  // 🔥 قاعدة الـ GET الصارمة: لو الرابط GET ومعندوش بارامترات، مستحيل نفحص فيه IDOR آلياً
  const hasUrlParams = /[?&][a-zA-Z0-9_-]+=/i.test(url);
  if (method === 'GET' && !hasUrlParams) {
    return false;
  }

  // ❌ قائمة الحظر لثغرات bWAPP الأخرى والروابط العامة
  const nonIdorBugs = ['sqli', 'xss', 'csrf', 'htmli', 'commandi', 'captcha', 'ldap', 'xml', 'ssrf', 'clickjacking', 'bof', 'phpi'];
  const generalBlacklist = ['logout', 'search', 'lang', 'contact', 'about', 'help', 'footer', 'menu'];

  const isBlacklisted = nonIdorBugs.some(bug => filename.includes(bug)) || 
                        generalBlacklist.some(word => filename.includes(word));
  if (isBlacklisted) return false;

  // قراءة متغيرات الـ Body للـ POST
  let bodyKeys = [];
  if (ep.body_params && typeof ep.body_params === 'object') {
    bodyKeys = Object.keys(ep.body_params).map(k => k.toLowerCase());
  }

  // 🎯 الكلمات الدلالية الصارمة لمعرفات الكيانات (Identifiers)
  const idorKeywords = [
    'id', 'user', 'login', 'account', 'ticket', 'order', 'doc', 'file', 
    'profile', 'secret', 'email', 'ref', 'token', 'member', 'invoice', 'object'
  ];

  // فحص الكلمات بحدود صارمة (منع التداخل)
  const matchKeywordStrict = (str) => {
    return idorKeywords.some(kw => {
      // الـ Regex ده بيضمن إن الكلمة جاية لوحدها مش مشتبكة في حروف تانية
      const regex = new RegExp('(^|[^a-z0-9])' + kw + '([^a-z0-9]|$)', 'i');
      return regex.test(str);
    });
  };

  const filenameHasKeyword = matchKeywordStrict(filename);
  const bodyHasKeyword = bodyKeys.some(key => matchKeywordStrict(key));

  // الـ POST يدخل فقط لو بيتعامل مع معرف كيان واضح في الـ Body أو الـ URL
  if (method === 'POST') {
    return (bodyKeys.length > 0) && (filenameHasKeyword || bodyHasKeyword);
  }

  return hasUrlParams && (filenameHasKeyword || bodyHasKeyword);
});

// 2. مرحلة إزالة التكرار الهيكلي (Deduplication)
const uniqueEndpoints = [];
const seenPatterns = new Set();

suspicious.forEach(ep => {
  const url = ep.url || '';
  const method = (ep.method || 'GET').toUpperCase();
  let pattern = method + '|' + url;

  if (url.includes('?')) {
    const base = url.split('?')[0];
    const params = url.split('?')[1] || '';
    const paramKeys = params.split('&').map(p => p.split('=')[0]).sort().join(',');
    pattern = method + '|' + base + '?' + paramKeys;
  } else if (ep.body_params && typeof ep.body_params === 'object') {
    const bodyKeysSorted = Object.keys(ep.body_params).sort().join(',');
    pattern = method + '|' + url + '|' + bodyKeysSorted;
  }

  if (!seenPatterns.has(pattern)) {
    seenPatterns.add(pattern);

    if (ep.body_params && typeof ep.body_params === 'object') {
      const simplified = {};
      for (const [key, val] of Object.entries(ep.body_params)) {
        simplified[key] = (val !== null && typeof val === 'object' && val.value !== undefined) 
          ? val.value : val;
      }
      ep.body_params = simplified;
    }
    uniqueEndpoints.push(ep);
  }
});

const scanId = $('Webhook').first().json.body.scan_id;

if (uniqueEndpoints.length === 0) {
  return [{ json: { idor_found: false, scan_id: scanId } }];
}

return uniqueEndpoints.map(ep => ({ 
  json: { 
    url: ep.url, 
    method: ep.method, 
    parameters: ep.parameters, 
    body_params: ep.body_params
  } 
}));

const url = query.url;
const method = (query.method || 'GET').toUpperCase();
let body = query.body || query.body_params || null;

// 1. تحويل الـ JSON لـ URL-encoded عشان الـ PHP يفهمه
if (body) {
  let bodyObj = null;
  if (typeof body === 'string' && body.trim().startsWith('{')) {
    try { bodyObj = JSON.parse(body); } catch(e) {}
  } else if (typeof body === 'object') {
    bodyObj = body;
  }

  if (bodyObj) {
    body = Object.keys(bodyObj)
      .map(key => encodeURIComponent(key) + '=' + encodeURIComponent(bodyObj[key]))
      .join('&');
  }
}

// 2. سحب الكوكي من الـ Webhook
let cookieHeader = '';
try {
  const webhookData = $('Webhook').first().json.body;
  if (webhookData && webhookData.cookie) {
    cookieHeader = webhookData.cookie;
  }
} catch(e) {}

// 3. تنفيذ الريكويست
try {
  const response = await helpers.httpRequest({
    method: method,
    url: url,
    headers: {
      'Cookie': cookieHeader,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: (method === 'POST' && body) ? body : undefined,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  // 4. معالجة وتجهيز الرد للـ AI
  const text = (typeof response.body === 'string') ? response.body : JSON.stringify(response.body);

  // 🔥 التعديل الأول: تصنيف وفلترة الـ Inputs بشكل ذكي وصارم
  let hiddenInputs = [];
  let visibleInputs = [];

  const inputRegex = /<input([^>]+)>/gi;
  let match;
  while ((match = inputRegex.exec(text)) !== null) {
    let attrs = match[1];
    let nameMatch = attrs.match(/name=["']([^"']+)["']/i);
    let valueMatch = attrs.match(/value=["']([^"']*)["']/i);
    let typeMatch = attrs.match(/type=["']([^"']+)["']/i);

    if (nameMatch) {
      const name = nameMatch[1];
      const type = typeMatch ? typeMatch[1].toLowerCase() : 'text';
      const value = valueMatch ? valueMatch[1] : '';

      if (type === 'hidden') {
        hiddenInputs.push(`${name}="${value}"`);
      } else if (name !== 'form' && name !== 'action') { // طنش الأزرار العامة
        visibleInputs.push(`${name}="${value}"`);
      }
    }
  }

  // صياغة الحقول المكتشفة في سطور واضحة جداً للـ AI
  let structuralInfo = "";
  if (hiddenInputs.length > 0) structuralInfo += `\n[CRITICAL HIDDEN FIELDS]: ${hiddenInputs.join(', ')}`;
  if (visibleInputs.length > 0) structuralInfo += `\n[VISIBLE FIELDS]: ${visibleInputs.join(', ')}`;

  // 5. تنظيف نص الصفحة وقص القوائم
  let clean = text.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, "");
  clean = clean.replace(/<style\b[^<]*(?:(?!<\/style>)<[^<]*)*<\/style>/gi, "");
  clean = clean.replace(/<[^>]+>/g, " ");

  // قص القائمة الجانبية الطويلة بتاعت bWAPP
  if (clean.includes("Choose your bug:")) {
    let parts = clean.split("Choose your bug:");
    let subParts = parts[1].split("---------------------------");
    clean = parts[0] + " " + (subParts[1] || subParts[0]);
  }

  // ضغط المسافات
  clean = clean.replace(/\s+/g, " ").trim();

  // 🔥 التعديل التاني: تحديد حجم النص بـ 2500 حرف كحد أقصى لمنع الـ Context Overflow تماماً
  let clippedContent = clean.substring(0, 2500);
  if (clean.length > 2500) clippedContent += "... [Content Truncated for Brevity]";

  // 6. الرد النهائي المنظم والمثالي للـ AI Agent
  return `=== SERVER RESPONSE ===
Status Code: ${response.statusCode}
Content Length: ${text.length} bytes${structuralInfo}
Page Content Text: ${clippedContent}
=======================`;

} catch (error) {
  return "Error during fetch: " + error.message;
}
